    setExpanded(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const categories = [
    {
      id: 'ds',
      name: '数据流监控',
      icon: <Database size={16} className="text-amber-500" />,
      items: ['实时同步', '财务集成', '历史迁移']
    },
    {
      id: 'pages',
      name: '页面展现',
      icon: <FileText size={16} className="text-blue-500" />,
      items: ['电子表格', '仪表盘', '报表编辑器']
    },
    {
      id: 'logic',
      name: '流程逻辑',
      icon: <Workflow size={16} className="text-purple-500" />,
      items: ['工作流', '状态机']
    },
    {
      id: 'models',
      name: '数据模型',
      icon: <Cpu size={16} className="text-emerald-500" />,
      items: ['财务模型', '领域模型']
    }
  ];

  return (
    <div className="space-y-4">
      {/* Smart Search */}
      <div className="relative">
        <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
        <input 
          type="text" 
          placeholder="搜索资源..." 
          className="w-full bg-slate-100 border-none rounded-lg py-1.5 pl-9 pr-3 text-xs focus:ring-2 focus:ring-blue-500/20 transition-shadow outline-none"
        />
        <button className="absolute right-2 top-1/2 -translate-y-1/2 p-0.5 hover:bg-slate-200 rounded text-slate-400">
          <Filter size={12} />
        </button>
      </div>

      <div className="space-y-1">
        {categories.map((cat) => (
          <div key={cat.id} className="space-y-0.5">
            <button 
              onClick={() => toggle(cat.id)}
              className="w-full flex items-center gap-2 p-1.5 hover:bg-white hover:shadow-sm rounded-md transition-all text-slate-700 font-medium group"
            >
              {expanded[cat.id] ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
              {cat.icon}
              <span className="text-xs truncate">{cat.name}</span>
            </button>

            {expanded[cat.id] && (
              <div className="pl-6 space-y-0.5 animate-in slide-in-from-top-1 duration-200">
                {cat.items.map((item, idx) => (
                  <button 
                    key={idx}
                    className="w-full text-left text-[11px] py-1.5 px-2 text-slate-500 hover:text-blue-600 hover:bg-blue-50/50 rounded transition-colors truncate"
