    { id: 'elements', icon: <Blocks size={20} />, label: '元素管理' },
  ] as const;

  // User Mode Navigation
  const userItems = [
    { id: 'elements', icon: <AppWindow size={20} />, label: '我的应用' },
    { id: 'search', icon: <Search size={20} />, label: '搜索资源' },
  ] as const;

  const renderNavItems = (items: readonly { id: ModuleId, icon: React.ReactNode, label: string }[]) => (
    <div className="px-3 flex flex-col gap-1">
      {items.map((item) => (
        <button
          key={item.id}
          onClick={() => onModuleChange(item.id)}
          className={`flex items-center rounded-xl transition-all duration-200 group relative min-h-[40px] ${
            activeModule === item.id 
              ? interfaceMode === 'dev' ? 'bg-blue-50 text-blue-600 shadow-sm' : 'bg-emerald-50 text-emerald-600 shadow-sm'
              : 'text-slate-400 hover:bg-slate-50 hover:text-slate-600'
          } ${isExpanded ? 'px-3 py-2 w-full' : 'p-2.5 justify-center'}`}
          title={!isExpanded ? item.label : ''}
        >
          <span className={`${activeModule === item.id ? 'scale-110' : 'scale-100'} transition-transform shrink-0`}>
            {item.icon}
          </span>

          {isExpanded && (
            <span className="ml-3 text-sm font-medium whitespace-nowrap animate-in fade-in slide-in-from-left-1 duration-200">
              {item.label}
            </span>
          )}

          {!isExpanded && (
            <div className="absolute left-full ml-3 px-2 py-1 bg-slate-800 text-white text-[10px] rounded opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity whitespace-nowrap z-50 shadow-lg">
              {item.label}
            </div>
          )}

          {activeModule === item.id && !isExpanded && (
            <div className={`absolute right-0 top-1/2 -translate-y-1/2 w-1 h-6 ${interfaceMode === 'dev' ? 'bg-blue-600' : 'bg-emerald-600'} rounded-l-full`}></div>
          )}
        </button>
      ))}
    </div>
  );

  return (
    <aside 
      className={`relative h-full border-r border-slate-200 flex flex-col transition-all duration-300 ease-in-out bg-white shrink-0 z-30 shadow-[4px_0_15px_-3px_rgba(0,0,0,0.03)] ${
        isExpanded ? 'w-60' : 'w-16'
      }`}
    >
      {/* Brand / Logo Area */}
      <div className="h-14 flex items-center px-3 border-b border-slate-50 shrink-0">
        <div className={`w-10 h-10 bg-gradient-to-br ${interfaceMode === 'dev' ? 'from-blue-600 to-indigo-700' : 'from-emerald-500 to-teal-600'} rounded-xl flex items-center justify-center text-white shadow-md ring-2 ring-white ring-offset-1 shrink-0`}>
          <Layers size={22} strokeWidth={2.5} />
        </div>
        {isExpanded && (
          <div className="ml-3 animate-in fade-in slide-in-from-left-2 duration-300 truncate">
            <span className="font-bold text-slate-800 tracking-tight block leading-tight">NovaFlow</span>
            <span className="text-[10px] text-slate-400 font-medium uppercase tracking-wider">
              {interfaceMode === 'dev' ? 'Low-Code Dev' : 'Runtime'}
            </span>
          </div>
        )}
      </div>

      {/* Main Navigation Scrollable */}
      <div className="flex-1 flex flex-col py-4 overflow-y-auto overflow-x-hidden gap-6">
        {interfaceMode === 'dev' ? (
          <>
            {/* Upper: Creation Tools */}
            {renderNavItems(devCreationItems)}

            {/* Divider with Label */}
            <div className="flex items-center px-4 shrink-0">
              <div className="h-[1px] bg-slate-100 flex-1" />
              {isExpanded && <span className="text-[9px] text-slate-300 font-bold uppercase tracking-widest px-2">Core</span>}
              <div className="h-[1px] bg-slate-100 flex-1" />
            </div>

            {/* Lower: Core Functions */}
            {renderNavItems(devCoreItems)}
          </>
        ) : (
          renderNavItems(userItems)
        )}
      </div>

      {/* Bottom Actions Area */}
      <div className="p-3 border-t border-slate-50 bg-slate-50/30 flex flex-col gap-2">
        {/* Expand Toggle */}
        <button
          onClick={onToggleExpand}
          className={`flex items-center gap-3 p-2.5 rounded-xl text-slate-400 hover:bg-white hover:text-slate-600 hover:shadow-sm transition-all ${!isExpanded && 'justify-center'}`}
        >
          {isExpanded ? <ChevronLeft size={20} /> : <ChevronRight size={20} />}
          {isExpanded && <span className="text-sm font-medium">收起侧边栏</span>}
        </button>

        {/* Mode Switcher */}
        <button
          onClick={onModeToggle}
          className={`flex items-center gap-3 p-2.5 rounded-xl transition-all ${
            interfaceMode === 'dev' 
            ? 'bg-blue-600 text-white shadow-md shadow-blue-200' 
            : 'bg-emerald-600 text-white shadow-md shadow-emerald-200'
          } ${!isExpanded && 'justify-center'}`}
        >
          <ArrowLeftRight size={20} />
          {isExpanded && (
            <div className="flex flex-col items-start leading-none text-left">
              <span className="text-[10px] opacity-70 font-medium uppercase tracking-tighter">当前模式</span>
              <span className="text-xs font-bold">{interfaceMode === 'dev' ? '开发者模式' : '使用者模式'}</span>
            </div>
          )}
        </button>

        <button className={`flex items-center gap-3 p-2.5 text-slate-400 hover:text-slate-600 transition-colors ${!isExpanded && 'justify-center'}`}>
          <Settings size={20} />
          {isExpanded && <span className="text-sm font-medium">全局设置</span>}
        </button>
      </div>
    </aside>
  );
};

