      <div className="p-3 border-t border-slate-50 bg-slate-50/30 flex flex-col gap-2 shrink-0">
        <button onClick={onToggleExpand} className={`flex items-center gap-3 p-2.5 rounded-xl text-slate-400 hover:bg-white hover:text-slate-600 hover:shadow-sm transition-all ${!isExpanded && 'justify-center'}`}>
          {isExpanded ? <ChevronLeft size={20} /> : <ChevronRight size={20} />}
          {isExpanded && <span className="text-sm font-medium">收起侧边栏</span>}
        </button>
        <button onClick={onModeToggle} className={`flex items-center gap-3 p-2.5 rounded-xl transition-all bg-slate-800 text-white shadow-md shadow-slate-200 ${!isExpanded && 'justify-center'}`}>
          <ArrowLeftRight size={20} />
          {isExpanded && (
            <div className="flex flex-col items-start leading-none text-left">
              <span className="text-[10px] opacity-70 font-medium uppercase tracking-tighter">当前模式</span>
              <span className="text-xs font-bold">{interfaceMode === 'dev' ? '开发者模式' : '使用者模式'}</span>
