        </button>
        <button className={`flex items-center gap-3 p-2.5 text-slate-400 hover:text-slate-600 transition-colors ${!isExpanded && 'justify-center'}`}>
          <Settings size={20} />
          {isExpanded && <span className="text-sm font-medium">全局设置</span>}
        </button>
      </div>
    </aside>
  );
};

