import { ViewMode, ResourceItem, ModuleId, Tab } from './types';
import Sidebar from './components/Sidebar';
import Explorer from './components/Explorer';
import MainContent from './components/MainContent';
import AIAssistant from './components/AIAssistant';

const INITIAL_DATA: ResourceItem[] = [
  {
    id: 'f1', name: '0101 每日定时从业务系统同步', type: 'folder', description: '每日定时从业务系统同步开票数据...', version: '-', createdBy: 'liuqing', updatedAt: '2025-10-14 17:28:07', unreadCount: 2, tags: ['Automated', 'Finance']
  },
  {
    id: 'f2', name: '0102 财务报表集成接口', type: 'connector', description: '财务报表集成数据流核心连接器', version: 'v1.0.2', createdBy: 'liuqing', updatedAt: '2025-10-14 17:28:09',
  },
  {
    id: 'f3', name: '财务模型-年度预算表', type: 'model', description: '2025年度财务预算核心模型', version: '3.0', createdBy: 'liuqing', updatedAt: '2025-10-23 10:38:41',
  }
];

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.EXPLORER);
  const [activeModule, setActiveModule] = useState<ModuleId>('elements');
  const [isAIShowing, setIsAIShowing] = useState(false);
  const [isSidebarExpanded, setIsSidebarExpanded] = useState(false);
  const [interfaceMode, setInterfaceMode] = useState<'dev' | 'user'>('dev');

  // Multi-tab state
  const [tabs, setTabs] = useState<Tab[]>([
    { id: 'default-elements', title: '元素管理', type: 'component', moduleId: 'elements' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('default-elements');

  const openTab = (item: ResourceItem | { id: string, name: string, type: any, moduleId?: ModuleId }) => {
    const existing = tabs.find(t => t.id === item.id);
    if (!existing) {
      // Use 'in' operator to safely check if moduleId exists in the union type parameter
      const moduleId = 'moduleId' in item ? item.moduleId : undefined;
      setTabs([...tabs, { id: item.id, title: item.name, type: item.type, moduleId }]);
    }
    setActiveTabId(item.id);
  };

  const closeTab = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newTabs = tabs.filter(t => t.id !== id);
    if (newTabs.length > 0) {
      if (activeTabId === id) {
        setActiveTabId(newTabs[newTabs.length - 1].id);
      }
      setTabs(newTabs);
    }
  };

  const moduleNames: Record<ModuleId, string> = {
    data: '数据模型',
    pages: '页面布局',
    process: '业务流程',
    logic: '逻辑编排',
    integration: '数据集成',
    elements: '元素管理',
    recents: '最近/收藏',
    terminal: '终端控制台',
    assets: '资源库'
  };

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-white selection:bg-blue-100">
      <Sidebar 
        activeModule={activeModule} 
        onModuleChange={(id) => {
          setActiveModule(id);
          // Auto-open module tab if it doesn't exist
          openTab({ id: `module-${id}`, name: moduleNames[id], type: 'folder', moduleId: id });
        }} 
        isExpanded={isSidebarExpanded}
        onToggleExpand={() => setIsSidebarExpanded(!isSidebarExpanded)}
        interfaceMode={interfaceMode}
        onModeToggle={() => setInterfaceMode(interfaceMode === 'dev' ? 'user' : 'dev')}
      />

      {interfaceMode === 'dev' && (
        <div className="flex flex-col border-r border-slate-200 w-72 shrink-0 bg-slate-50/50">
          <div className="h-14 flex items-center px-4 justify-between border-b border-slate-200 bg-white">
            <span className="font-bold text-slate-800 tracking-tight flex items-center gap-2">
              <div className="w-6 h-6 bg-blue-600 rounded flex items-center justify-center">
                <Boxes size={14} className="text-white" />
              </div>
              {moduleNames[activeModule]}
            </span>
          </div>
          <div className="flex-1 overflow-hidden relative">
            {/* Contextual Directory Switch with Animation */}
            <div key={activeModule} className="absolute inset-0 p-3 overflow-y-auto animate-in slide-in-from-bottom-4 duration-300">
              <Explorer activeModule={activeModule} onSelectResource={(item) => openTab(item)} />
            </div>
          </div>
        </div>
      )}

      <div className="flex-1 flex flex-col min-w-0">
        <header className="h-14 flex items-center justify-between border-b border-slate-200 bg-white shrink-0 z-10">
          {/* Tab Bar */}
          <div className="flex-1 flex h-full overflow-x-auto no-scrollbar items-end px-2 gap-1 bg-slate-50/50">
            {tabs.map((tab) => (
              <div 
                key={tab.id}
                onClick={() => setActiveTabId(tab.id)}
                className={`group h-10 flex items-center px-4 gap-2 text-xs font-medium cursor-pointer transition-all border-t-2 rounded-t-lg shrink-0 ${
                  activeTabId === tab.id 
                    ? 'bg-white border-blue-600 text-blue-700 shadow-sm' 
                    : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-200/50'
                }`}
              >
                <Files size={14} className={activeTabId === tab.id ? 'text-blue-600' : 'text-slate-400'} />
                <span className="max-w-[120px] truncate">{tab.title}</span>
                <button 
                  onClick={(e) => closeTab(e, tab.id)}
                  className="p-0.5 rounded-full hover:bg-slate-200 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <X size={12} />
                </button>
              </div>
            ))}
          </div>

          <div className="flex items-center gap-2 px-4 border-l border-slate-100 bg-white h-full">
            <div className="flex bg-slate-100 p-1 rounded-lg border border-slate-200">
              <button onClick={() => setViewMode(ViewMode.EXPLORER)} className={`p-1.5 rounded-md text-xs font-medium transition-all ${viewMode === ViewMode.EXPLORER ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                <Files size={14} />
              </button>
              <button onClick={() => setViewMode(ViewMode.DESIGN)} className={`p-1.5 rounded-md text-xs font-medium transition-all ${viewMode === ViewMode.DESIGN ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                <PencilRuler size={14} />
              </button>
              <button onClick={() => setViewMode(ViewMode.PREVIEW)} className={`p-1.5 rounded-md text-xs font-medium transition-all ${viewMode === ViewMode.PREVIEW ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                <MonitorPlay size={14} />
              </button>
            </div>
            <button onClick={() => setIsAIShowing(!isAIShowing)} className={`p-2 rounded-full transition-colors ${isAIShowing ? 'bg-blue-50 text-blue-600' : 'text-slate-400 hover:bg-slate-100'}`}>
              <Sparkles size={18} />
            </button>
            <button className="p-2 text-slate-400 hover:bg-slate-100 rounded-full">
              <Bell size={18} />
            </button>
            <div className="w-8 h-8 rounded-full bg-indigo-500 flex items-center justify-center text-white text-xs font-bold border-2 border-white shadow-sm ml-2 shrink-0">LQ</div>
          </div>
        </header>

        <main className="flex-1 flex flex-row overflow-hidden relative">
          <div className="flex-1 overflow-hidden">
            {/* The active tab's moduleId or context determines what MainContent shows */}
            <MainContent 
              data={INITIAL_DATA} 
              viewMode={viewMode} 
              activeTab={tabs.find(t => t.id === activeTabId)} 
            />
          </div>
          {isAIShowing && (
            <div className="w-80 border-l border-slate-200 bg-white shrink-0 animate-in slide-in-from-right duration-300 z-10 shadow-xl">
              <AIAssistant onClose={() => setIsAIShowing(false)} />
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

