  type: ResourceType;
  description?: string;
  version: string;
  createdBy: string;
  updatedAt: string;
  children?: ResourceItem[];
  status?: 'active' | 'draft' | 'archived';
  unreadCount?: number;
  tags?: string[];
}

export interface Tab {
  id: string;
  title: string;
  type: ResourceType | 'module';
  moduleId?: ModuleId;
}

export enum ViewMode {
  EXPLORER = 'explorer',
