const INITIAL_DATA: ResourceItem[] = [
  {
    id: 'f1', name: '0101 每日定时对账核销任务', type: 'workflow', description: '自动从ERP拉取流水并进行匹配...', version: 'v2.1', createdBy: 'liuqing', updatedAt: '2025-05-14 10:28:07', unreadCount: 1, tags: ['Finance', 'Batch']
  },
  {
    id: 'f2', name: '财务报表集成接口', type: 'connector', description: '财务报表集成数据流核心连接器', version: 'v1.0.2', createdBy: 'liuqing', updatedAt: '2025-05-14 17:28:09',
  },
  {
    id: 'f3', name: '对账核销模型-核心逻辑', type: 'model', description: '核心清算与对账业务模型', version: '3.0', createdBy: 'liuqing', updatedAt: '2025-05-23 10:38:41',
  }
];

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<ModuleId>('data');
  const [activeDrawerModule, setActiveDrawerModule] = useState<ModuleId | null>('recents');
  const [isAIShowing, setIsAIShowing] = useState(false);
  const [isSidebarExpanded, setIsSidebarExpanded] = useState(false);
  const [interfaceMode, setInterfaceMode] = useState<'dev' | 'user'>('dev');

  // Multi-tab state
  const [tabs, setTabs] = useState<Tab[]>([
    { id: 'default-home', title: '领域模型', type: 'folder', moduleId: 'data' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('default-home');

  const openTab = (item: ResourceItem | { id: string, name: string, type: any, moduleId?: ModuleId }) => {
    const existing = tabs.find(t => t.id === item.id);
    if (!existing) {
      const moduleId = 'moduleId' in item ? item.moduleId : undefined;
      setTabs([...tabs, { id: item.id, title: item.name, type: item.type, moduleId }]);
    }
    setActiveTabId(item.id);
  };

  const closeTab = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newTabs = tabs.filter(t => t.id !== id);
    if (newTabs.length > 0) {
      if (activeTabId === id) {
        setActiveTabId(newTabs[newTabs.length - 1].id);
      }
      setTabs(newTabs);
    }
  };

  const moduleNames: Record<ModuleId, string> = {
    pages: '页面展现',
    logic: '流程逻辑',
    data: '数据模型',
    lakehouse: '数据湖仓',
    integration: '数据集成',
    services: '基础服务',
    v2: 'V2组件',
    finance: '场景-财务工具',
    recents: '最近打开与搜藏',
    elements: '元素管理'
  };

  return (
    <div className="flex flex-col h-screen w-screen overflow-hidden bg-white selection:bg-blue-100 antialiased font-sans text-[13px]">
      {/* Top Header - Spans across Sidebar and Explorer area as requested */}
      <header className="h-11 flex items-center bg-[#f3f4f9] border-b border-slate-200 shrink-0 z-50">
        <div className={`${isSidebarExpanded ? 'w-56' : 'w-14'} flex items-center px-3 border-r border-slate-200 transition-all duration-300 h-full bg-white`}>
           <Menu size={18} className="text-slate-500 cursor-pointer" />
           {isSidebarExpanded && <span className="ml-3 font-bold text-slate-800 text-[14px]">DeepFos</span>}
        </div>
        <div className="flex-1 flex items-center px-4 gap-3">
          <div className="w-6 h-6 bg-[#9370db] rounded flex items-center justify-center text-white">
            <Boxes size={14} />
          </div>
          <span className="font-bold text-slate-800">{moduleNames[activeModule]}</span>
        </div>
        <div className="flex items-center gap-4 px-5 shrink-0">
          <button onClick={() => setIsAIShowing(!isAIShowing)} className={`p-1 rounded-lg transition-colors ${isAIShowing ? 'bg-blue-50 text-blue-600' : 'text-slate-400 hover:bg-slate-200'}`}>
            <Sparkles size={18} />
          </button>
          <button className="p-1 text-slate-400 hover:bg-slate-200 rounded-lg relative">
            <Bell size={18} />
            <div className="absolute top-0 right-0 w-2 h-2 bg-red-500 rounded-full border border-white"></div>
          </button>
          <div className="w-7 h-7 rounded-full bg-blue-600 flex items-center justify-center text-white text-[11px] font-bold border border-white shadow-sm">LQ</div>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <Sidebar 
          activeModule={activeModule} 
          onModuleChange={(id) => {
            setActiveModule(id);
            openTab({ id: `module-${id}`, name: moduleNames[id], type: 'folder', moduleId: id });
          }} 
          activeDrawerModule={activeDrawerModule}
          onDrawerChange={(id) => {
            setActiveDrawerModule(activeDrawerModule === id ? null : id);
          }}
          isExpanded={isSidebarExpanded}
          onToggleExpand={() => setIsSidebarExpanded(!isSidebarExpanded)}
          interfaceMode={interfaceMode}
          onModeToggle={(mode) => {
            setInterfaceMode(mode);
            setActiveModule(mode === 'dev' ? 'data' : 'finance');
          }}
        />

        {/* Directory/Explorer Area */}
        {interfaceMode === 'dev' && (
          <div className="flex flex-col border-r border-slate-200 w-64 shrink-0 bg-white relative overflow-hidden">
            <div className="flex-1 flex flex-col min-h-0">
              <div className="flex-1 overflow-y-auto p-0 scrollbar-hide">
                <Explorer 
                  key={`${activeModule}-${interfaceMode}`} 
                  activeModule={activeModule} 
                  onSelectResource={(item) => openTab(item)}
                  isUserMode={interfaceMode === 'user'} 
                />
              </div>
            </div>

            <div className={`border-t border-slate-200 bg-slate-50 transition-all duration-300 ease-in-out flex flex-col ${
              activeDrawerModule ? 'h-[35%]' : 'h-0'
            }`}>
              <div className="h-8 flex items-center px-4 justify-between border-b border-slate-200 bg-white shrink-0">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                  {activeDrawerModule ? moduleNames[activeDrawerModule] : ''}
                </span>
                <button onClick={() => setActiveDrawerModule(null)} className="p-1 hover:bg-slate-100 rounded text-slate-400">
                  <ChevronDown size={14} />
                </button>
              </div>
              <div className="flex-1 overflow-y-auto p-0">
                {activeDrawerModule && (
                  <Explorer 
                    key={activeDrawerModule} 
                    activeModule={activeDrawerModule} 
                    onSelectResource={(item) => openTab(item)} 
                  />
                )}
              </div>
            </div>
          </div>
        )}

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col min-w-0 bg-[#f8fafc]">
          <header className="h-10 flex items-center justify-between border-b border-slate-200 bg-white shrink-0 z-10 px-2">
            <div className="flex-1 flex h-full overflow-x-auto no-scrollbar items-end gap-0.5">
              {tabs.map((tab) => (
                <div 
                  key={tab.id}
                  onClick={() => setActiveTabId(tab.id)}
                  className={`group h-[32px] flex items-center px-3 gap-2 text-[12px] font-medium cursor-pointer transition-all border-t-2 rounded-t-md shrink-0 ${
                    activeTabId === tab.id 
                      ? 'bg-white border-blue-600 text-blue-700 shadow-sm' 
                      : 'bg-transparent border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Files size={12} className={activeTabId === tab.id ? 'text-blue-600' : 'text-slate-400'} />
                  <span className="max-w-[120px] truncate">{tab.title}</span>
                  <button 
                    onClick={(e) => closeTab(e, tab.id)}
                    className="p-0.5 rounded-full hover:bg-slate-100 opacity-0 group-hover:opacity-100 transition-opacity ml-1"
                  >
                    <X size={10} />
                  </button>
                </div>
              ))}
            </div>
          </header>

          <main className="flex-1 flex flex-row overflow-hidden relative">
            <div className="flex-1 overflow-hidden">
              <MainContent 
                data={INITIAL_DATA} 
                viewMode={ViewMode.EXPLORER} 
                activeTab={tabs.find(t => t.id === activeTabId)} 
              />
            </div>
            {isAIShowing && (
              <div className="w-80 border-l border-slate-200 bg-white shrink-0 animate-in slide-in-from-right duration-300 z-10 shadow-xl">
                <AIAssistant onClose={() => setIsAIShowing(false)} />
              </div>
            )}
          </main>
        </div>
      </div>
    </div>
  );
};

export default App;

