const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<ModuleId>('data');
  const [activeDrawerModule, setActiveDrawerModule] = useState<ModuleId | null>('context');
  const [isAIShowing, setIsAIShowing] = useState(false);
  const [interfaceMode, setInterfaceMode] = useState<'dev' | 'user'>('dev');

  const [isNavHidden, setIsNavHidden] = useState(false);
  const [sidebarWidth, setSidebarWidth] = useState(64);
  const [isResizing, setIsResizing] = useState(false);
  const isExpanded = sidebarWidth > 120;

  const [tabs, setTabs] = useState<Tab[]>([
    { id: 'elements-view', title: '元素管理', type: 'folder' }
  ]);
  const [activeTabId, setActiveTabId] = useState<string | null>('elements-view');

  const activeTab = useMemo(() => tabs.find(t => t.id === activeTabId), [tabs, activeTabId]);

  const resize = useCallback((e: MouseEvent) => {
    if (isResizing) {
      const newWidth = Math.min(Math.max(64, e.clientX), 320);
      setSidebarWidth(newWidth);
    }
  }, [isResizing]);

  const stopResizing = useCallback(() => setIsResizing(false), []);

  useEffect(() => {
    if (isResizing) {
      window.addEventListener('mousemove', resize);
      window.addEventListener('mouseup', stopResizing);
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
    } else {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    }
    return () => {
      window.removeEventListener('mousemove', resize);
      window.removeEventListener('mouseup', stopResizing);
    };
  }, [isResizing, resize, stopResizing]);

  const openTab = useCallback((item: ResourceItem | { id: string, name: string, code?: string, type: any, moduleId?: ModuleId, updatedAt?: string }) => {
    setTabs(prevTabs => {
      const existing = prevTabs.find(t => t.id === item.id);
      if (!existing) {
        return [...prevTabs, { 
          id: item.id, 
          title: item.name, 
          code: item.code, 
          type: item.type, 
          moduleId: 'moduleId' in item ? item.moduleId : undefined,
          updatedAt: item.updatedAt
        }];
      }
      return prevTabs;
    });
    setActiveTabId(item.id);
  }, []);

  const closeTab = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const newTabs = tabs.filter(t => t.id !== id);
    if (newTabs.length > 0) {
      if (activeTabId === id) setActiveTabId(newTabs[newTabs.length - 1].id);
    } else setActiveTabId(null);
    setTabs(newTabs);
  };

  const moduleNames: Record<ModuleId, string> = {
    pages: '页面展现',
    logic: '流程逻辑',
    data: '数据模型',
    lakehouse: '数据湖仓',
    integration: '数据集成',
    services: '基础服务',
    v2: 'V2组件',
    finance: '场景-财务工具',
    recents: '最近打开与搜藏',
    elements: '元素管理',
    resources: '全量资源',
    terminal: '终端',
    context: '关联上下文'
  };

  const navContainerWidth = sidebarWidth + 240;

  return (
    <div className="flex flex-col h-screen w-screen overflow-hidden bg-white selection:bg-blue-100 antialiased font-sans text-[13px]">
      {/* Top Brand Header spans Sidebar + Explorer area */}
      <header className="h-11 flex items-center border-b border-slate-200 bg-[#f9f9fc] shrink-0 z-40">
        <div className={`flex items-center px-4 h-full border-r border-slate-200 bg-white transition-all duration-300 overflow-hidden ${isNavHidden ? 'w-0 border-r-0 px-0' : (isExpanded ? 'w-56' : 'w-14')}`}>
          <Menu size={18} className="text-slate-500 shrink-0" />
          {isExpanded && <span className="ml-3 font-black text-slate-800 tracking-tight text-[15px] whitespace-nowrap">DeepFos</span>}
        </div>

        <div className="flex-1 flex items-center px-4 gap-3 overflow-hidden">
          <div className="w-6 h-6 bg-blue-600 rounded flex items-center justify-center text-white shrink-0">
            <Boxes size={14} />
          </div>
          <span className="font-bold text-slate-800 whitespace-nowrap truncate">{moduleNames[activeModule]}</span>
        </div>

        <div className="flex items-center gap-4 px-5 shrink-0">
          <button onClick={() => setIsAIShowing(!isAIShowing)} className={`p-1.5 rounded transition-colors ${isAIShowing ? 'bg-blue-100 text-blue-600' : 'text-slate-400 hover:bg-slate-200'}`}>
            <Sparkles size={18} />
          </button>
          <button className="p-1.5 text-slate-400 hover:bg-slate-200 rounded relative">
            <Bell size={18} />
            <div className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border border-white"></div>
          </button>
          <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white text-[12px] font-bold border-2 border-white shadow-sm">LQ</div>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden relative">
        <div 
          className="flex h-full overflow-hidden transition-all duration-300 ease-in-out border-r border-slate-200 shrink-0 relative z-30 bg-white"
          style={{ 
            width: isNavHidden ? '0px' : `${navContainerWidth}px`,
            marginLeft: isNavHidden ? `-${navContainerWidth}px` : '0px'
          }}
        >
          <Sidebar 
            activeModule={activeModule} 
            onModuleChange={(id) => {
               setActiveModule(id as ModuleId);
               openTab({ id: `module-${id}`, name: moduleNames[id as ModuleId], type: 'folder', moduleId: id as ModuleId });
            }}
            activeDrawerModule={activeDrawerModule}
            onDrawerChange={(id) => setActiveDrawerModule(activeDrawerModule === id ? null : id)}
            width={sidebarWidth}
            isExpanded={isExpanded}
            onToggleExpand={() => setSidebarWidth(isExpanded ? 64 : 200)}
            onResizeStart={() => setIsResizing(true)}
            isResizing={isResizing}
            interfaceMode={interfaceMode}
            onModeToggle={(mode) => setInterfaceMode(mode)}
          />

          <div className="flex-1 flex flex-col border-l border-slate-100 bg-white overflow-hidden">
            <Explorer 
              activeModule={activeModule} 
              onSelectResource={openTab}
              isUserMode={interfaceMode === 'user'} 
              activeTab={activeTab}
              showContext={activeDrawerModule === 'context'}
              onCloseContext={() => setActiveDrawerModule(null)}
            />
          </div>
        </div>

        <div className="flex-1 flex flex-col min-w-0 bg-[#f8fafc] z-10">
          <header className="h-10 flex items-center justify-between border-b border-slate-200 bg-white shrink-0 px-2 overflow-hidden">
            <div className="flex-1 flex h-full overflow-x-auto no-scrollbar items-end gap-0.5">
              {tabs.map((tab) => (
                <div 
                  key={tab.id}
                  onClick={() => setActiveTabId(tab.id)}
                  className={`group h-[34px] flex items-center px-4 gap-2 text-[12px] font-medium cursor-pointer transition-all border-t-2 rounded-t-md shrink-0 ${
                    activeTabId === tab.id ? 'bg-white border-blue-600 text-blue-700 shadow-sm' : 'bg-transparent border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Files size={12} className={activeTabId === tab.id ? 'text-blue-600' : 'text-slate-400'} />
                  <span className="max-w-[140px] truncate">{tab.title}</span>
                  <button onClick={(e) => closeTab(e, tab.id)} className="p-0.5 rounded-full hover:bg-slate-100 opacity-0 group-hover:opacity-100 transition-opacity ml-1">
                    <X size={10} />
                  </button>
                </div>
              ))}
            </div>
            <button onClick={() => setIsNavHidden(!isNavHidden)} className="p-1.5 text-slate-400 hover:bg-slate-50 rounded ml-2">
              {isNavHidden ? <PanelLeft size={16} /> : <PanelLeftClose size={16} />}
            </button>
          </header>

          <main className="flex-1 overflow-hidden relative">
            <MainContent data={INITIAL_DATA} viewMode={ViewMode.EXPLORER} activeTab={activeTab} onOpenTab={openTab} />
          </main>
        </div>

        {isAIShowing && (
          <div className="w-80 border-l border-slate-200 bg-white shrink-0 animate-in slide-in-from-right duration-300 z-40 shadow-xl">
            <AIAssistant onClose={() => setIsAIShowing(false)} />
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

