          </button>
        </div>
        <button onClick={onToggleExpand} className={`flex items-center gap-3 p-2 rounded text-slate-400 hover:text-slate-600 transition-all ${!isExpanded && 'justify-center'}`}>
          {isExpanded ? <ChevronLeft size={18} /> : <ChevronRight size={18} />}
          {isExpanded && <span className="text-[12px] font-bold">收起</span>}
        </button>
      </div>
    </aside>
  );
};

