            </div>
          </div>
          {hasChildren && isExpanded && (
            <div className="ml-4 border-l border-slate-100">
              {renderTree(item.items, level + 1)}
            </div>
          )}
        </div>
      );
    });
  };

  const currentItems = isUserMode ? [] : (moduleRoots[activeModule] || []);

  return (
    <div className="flex flex-col h-full bg-white">
      {/* Directory Search */}
      <div className="p-3 border-b border-slate-100 flex items-center gap-2 bg-slate-50/30">
