          <Plus size={16} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto py-2 no-scrollbar">
        {currentItems.length > 0 ? (
          renderTree(currentItems)
        ) : (
          <div className="p-8 text-center text-slate-400 italic text-[11px]">
            暂无子项目
          </div>
        )}
      </div>

      {showContext && (
